import { coerce } from "./coerce.js";

/**
 * Validates and coerces environment variables against a schema.
 *
 * @param {Record<string, string>} env - Raw environment variables
 * @param {Record<string, SchemaEntry>} schema - Validation schema
 * @param {boolean} strict - If true, disallow variables not in schema
 * @returns {{ result: Record<string, any>, errors: string[] }}
 */
export function validate(env, schema, strict = false) {
  const errors = [];
  const result = {};

  // Validate each schema entry
  for (const [key, rule] of Object.entries(schema)) {
    let raw = env[key];

    // Apply default if missing
    if (raw === undefined || raw === "") {
      if (rule.default !== undefined) {
        raw = String(rule.default);
      }
    }

    // Check required
    if (rule.required && (raw === undefined || raw === "")) {
      errors.push(`${key} is required but missing`);
      continue;
    }

    // Skip optional missing vars
    if (raw === undefined || raw === "") {
      continue;
    }

    // Type coercion
    const type = rule.type || "string";
    const { value, error } = coerce(raw, type);

    if (error) {
      errors.push(`${key} ${error}`);
      continue;
    }

    // Enum validation (works on the coerced value for strings, raw for others)
    if (rule.enum) {
      const checkVal = type === "string" ? value : raw;
      if (!rule.enum.includes(checkVal) && !rule.enum.map(String).includes(String(checkVal))) {
        errors.push(
          `${key} must be one of [${rule.enum.map((v) => `"${v}"`).join(", ")}] (received "${raw}")`
        );
        continue;
      }
    }

    // Custom validator
    if (typeof rule.validate === "function") {
      let pass;
      try {
        pass = rule.validate(value);
      } catch (e) {
        errors.push(`${key} failed custom validation: ${e.message}`);
        continue;
      }
      if (pass === false) {
        errors.push(`${key} failed custom validation (received "${raw}")`);
        continue;
      }
    }

    result[key] = value;
  }

  // Strict mode: reject unknown keys
  if (strict) {
    const knownKeys = new Set(Object.keys(schema));
    for (const key of Object.keys(env)) {
      if (!knownKeys.has(key)) {
        errors.push(`${key} is not allowed in strict mode`);
      }
    }
  }

  return { result, errors };
}
